    def _sort_palette(self, sort_palette):
        """
        Reorders this image's palette according to ``sort_palette``, and
        remaps the pixel data to match. See :py:meth:`~PIL.Image.Image.quantize`
        for the supported values of ``sort_palette``.
        """
        source_palette = self.im.getpalette("RGB")[:768]
        colors = [source_palette[i * 3 : i * 3 + 3] for i in range(256)]

        if sort_palette == "brightness":

            def sort_key(color):
                r, g, b = color
                return r * 299 + g * 587 + b * 114

        elif sort_palette == "rgb":

            def sort_key(color):
                return tuple(color)

        else:
            raise ValueError("sort_palette must be 'brightness', 'rgb', or None")

        order = sorted(range(256), key=lambda i: sort_key(colors[i]))
        return self.remap_palette(order)

    def _adjust_palette_lightness(self, lightness_factor):
        """
        Adjusts the brightness of this image's palette entries in place by
        ``lightness_factor``. See :py:meth:`~PIL.Image.Image.quantize` for
        details.
        """
        palette = self.im.getpalette("RGB")[:768]
        adjusted = bytearray(len(palette))
        for i, value in enumerate(palette):
            adjusted[i] = max(0, min(255, round(value * lightness_factor)))
        self.putpalette(adjusted, "RGB")"}
